mapper.select:
SELECT id, project_status AS status, project_name, project_type, train_type AS trainType, train_way AS trainWay, IFNULL(train_sdate, IFNULL(practice_sdate, exam_sdate)) AS startDate, IFNULL(exam_edate, IFNULL(practice_edate, train_edate)) AS endDate, (SELECT COUNT(1) FROM xm_project_relate b WHERE b.project_id = a.id AND b.is_delete = 0 AND b.type = 3) AS personNum, (SELECT name FROM sys_user WHERE id = a.create_by) AS createBy, create_time AS createDate FROM xm_project a WHERE is_delete = 0 AND project_type = #{type}
AND project_name LIKE CONCAT('%', #{projectName}, '%')
AND project_status = #{status}
AND IFNULL(train_sdate, IFNULL(practice_sdate, exam_sdate)) > #{startDate}
AND IFNULL(train_sdate, IFNULL(practice_sdate, exam_sdate)) < #{endDate}
AND train_way = #{trainWay}
AND org_id IN
#{item}
AND org_id IN ( SELECT id FROM sys_org WHERE id = #{orgId} UNION SELECT id FROM sys_org WHERE pids LIKE CONCAT('%[', #{orgId}, ']%') )
ORDER BY create_time DESC

SELECT a.id, project_type, project_name, train_sdate, train_edate, train_type, '课堂讲师' as teacher, total_course_hours, a.remark, '/dawa/sys/oss/show/20220226/e37b7c2821cf4a9e904f2f502f7ee941.jpg' as coverImage from xm_project a WHERE a.is_delete = 0 and project_status > 2
and a.id = #{projectId}
and project_type = #{projectType} and year(a.train_sdate) = year(now())
